 18→// ── CodeBlock ─────────────────────────────────────────────────────
 19→// eslint-disable-next-line @typescript-eslint/no-explicit-any
 20→function CodeBlock({ inline, className, children, ...props }: any) {
 21→  const match = /language-(\w+)/.exec(className || "");
 22→  const [copied, setCopied] = useState(false);
 23→  
 24→  const hCopy = () => {
 25→    navigator.clipboard.writeText(String(children).replace(/\n$/, ""));
 26→    setCopied(true);
 27→    setTimeout(() => setCopied(false), 2000);
 28→  };
 29→
 30→  if (!inline && match) {
 31→    return (
 32→      <div className={`${s.codeBlockWrap} ${s.staggerBlock}`}>
 33→        <div className={s.codeHeader}>
 34→          <span className={s.codeLang}>{match[1]}</span>
 35→          <button className={s.codeCopyBtn} onClick={hCopy} aria-label="Copy code">
 36→            {copied ? "✓ Copied" : "Copy"}
 37→          </button>
 38→        </div>
 39→        <pre className={s.codePre}><code className={className} {...props}>{children}</code></pre>
 40→      </div>
 41→    );
 42→  }
 43→  return <code className={className} {...props}>{children}</code>;
 44→}
